-- +goose StatementBegin
-- Universal trade-station / pirbase market (phase 10.19 follow-up),
-- generated by cmd/starwind-tools/gen-trade-markets. Every built trade
-- station (owner_kind 4) and pirbase (owner_kind 5) trades every commodity
-- good: it buys any good from the player (buy_price) and sells any good it
-- has in stock (sell_price). Prices are FLAT — parity with the original
-- StarWind Trade SP (the dynamic avg<->max pricing of phase 10.18 stays
-- exclusive to production factories). Replaces the narrow 0036/0043 trade-
-- station seed and the 0027/0004 pirbase seed. Do not edit — rerun the tool.

DELETE FROM station_goods WHERE owner_kind IN (4, 5);

INSERT INTO station_goods (owner_kind, owner_id, goods_type_id, buy_price, sell_price, stock, max_stock)
SELECT o.owner_kind, o.owner_id, g.gid, g.buy_price, g.sell_price, 500, 1000000
FROM (
    SELECT 4 AS owner_kind, id AS owner_id FROM trade_stations WHERE built
    UNION ALL
    SELECT 5 AS owner_kind, id AS owner_id FROM pirbases WHERE built
) o
CROSS JOIN (VALUES
    (1, 8, 10),
    (2, 62, 75),
    (3, 252, 303),
    (4, 840, 1008),
    (5, 1485, 1634),
