    (104, 1, 2),
    (105, 1, 2),
    (112, 431, 518),
    (113, 31, 38),
    (114, 31, 38),
    (301, 506, 608),
    (302, 809, 971),
    (303, 3413, 4096),
    (304, 8550, 10260),
    (305, 20313, 24376),
