    (322, 9479027, 11374833)
) AS g(gid, buy_price, sell_price);

-- Pirbases also trade slaves (323): buy from the player, sell back at a
-- markup. Start with none in stock — buyable only once some are sold here.
INSERT INTO station_goods (owner_kind, owner_id, goods_type_id, buy_price, sell_price, stock, max_stock)
SELECT 5, pb.id, 323, 800, 1000, 0, 1000000000
FROM pirbases pb WHERE pb.built;
