-- +goose Down
-- +goose StatementBegin
-- Irreversible pre-release reseed: drops every trade-station / pirbase
-- market (the narrow 0036/0043/0027 seeds are not restored).
DELETE FROM station_goods WHERE owner_kind IN (4, 5);
